useEffect(() => {
  if (!sortRefreshAlignPendingRef.current) return undefined

  sortRefreshAlignPendingRef.current = false
  clearSortRefreshAlignHandles()

  const startUserScrollTs = (() => {
    try { return Number(window.__forumUserScrollTs || 0) } catch { return 0 }
  })()

  let cancelled = false
  const scheduleAlign = (attempt = 0) => {
    if (cancelled) return
    const currentUserScrollTs = (() => {
      try { return Number(window.__forumUserScrollTs || 0) } catch { return 0 }
    })()
    if (attempt > 0 && currentUserScrollTs > startUserScrollTs) return
    const aligned = !!runSortRefreshAlignment()
    if (aligned) return
    if (attempt >= 12) return
    const delay = attempt <= 1 ? 72 : (attempt <= 6 ? 130 : 200)
    const timerId = setTimeout(() => scheduleAlign(attempt + 1), delay)
    sortRefreshAlignTimersRef.current.push(timerId)
  }

  try {
    const rafA = requestAnimationFrame(() => {
      const rafB = requestAnimationFrame(() => scheduleAlign(0))
      sortRefreshAlignRafsRef.current.push(rafB)
    })
    sortRefreshAlignRafsRef.current.push(rafA)
  } catch {
    const timerId = setTimeout(() => scheduleAlign(0), 0)
    sortRefreshAlignTimersRef.current.push(timerId)
  }

  return () => {
    cancelled = true
    clearSortRefreshAlignHandles()
  }
}, [clearSortRefreshAlignHandles, contentRefreshToken, runSortRefreshAlignment])

React.useEffect(() => {
  const a = audioRef.current
  if (!a) return

  setPlaying(false)
  setDur(0)
  setPos(0)
  draggingRef.current = false
  stopRaf()
  stopDurationPoll()

  try {
    a.pause?.()
  } catch {}
  try {
    a.currentTime = 0
  } catch {}
  try {
    a.playbackRate = rateRef.current
  } catch {}

  const onLoaded = () => syncAudioMetrics(a)
  const onPlay = () => {
    setPlaying(true)
    syncAudioMetrics(a)
    startRaf()
  }
  const onPause = () => {
    setPlaying(false)
    stopRaf()
  }
  const onEnded = () => {
    setPlaying(false)
    stopRaf()
    setPos(0)
  }
  const onTimeUpdate = () => syncAudioMetrics(a)

  a.addEventListener('loadedmetadata', onLoaded)
  a.addEventListener('loadeddata', onLoaded)
  a.addEventListener('canplay', onLoaded)
  a.addEventListener('durationchange', onLoaded)
  a.addEventListener('progress', onLoaded)
  a.addEventListener('timeupdate', onTimeUpdate)
  a.addEventListener('play', onPlay)
  a.addEventListener('pause', onPause)
  a.addEventListener('ended', onEnded)
  durationPollRef.current = window.setInterval(() => syncAudioMetrics(a), 350)
  syncAudioMetrics(a)

  return () => {
    a.removeEventListener('loadedmetadata', onLoaded)
    a.removeEventListener('loadeddata', onLoaded)
    a.removeEventListener('canplay', onLoaded)
    a.removeEventListener('durationchange', onLoaded)
    a.removeEventListener('progress', onLoaded)
    a.removeEventListener('timeupdate', onTimeUpdate)
    a.removeEventListener('play', onPlay)
    a.removeEventListener('pause', onPause)
    a.removeEventListener('ended', onEnded)
    stopRaf()
    stopDurationPoll()
  }
}, [src, startRaf, stopDurationPoll, stopRaf, syncAudioMetrics])
